const model = $input.first().json.model || '';
const audioPath = $input.first().json.audio_path || '';

// Path traversal detection: check for ../, ..\\, and encoded variants
const pathTraversalPattern = /(\.\.[/\\]|%2e%2e[/\\]|\.\.\\x5c)/i;

// Check model name (alphanumeric, dash, underscore only)
const validModelPattern = /^[a-zA-Z0-9_\\-]+$/;

if (pathTraversalPattern.test(model) || pathTraversalPattern.test(audioPath)) {
  return [{
    json: {
      error: 'Path traversal detected: model and audio_path must not contain directory traversal sequences',
      status: 400
    }
  }];
}

if (model && !validModelPattern.test(model)) {
  return [{
    json: {
      error: 'Invalid model name: must be alphanumeric, dash, or underscore only',
      status: 400
    }
  }];
}

return [{
  json: {
    model: model || 'default',
    audio: $input.first().json.audio,
    audio_path: audioPath
  }
}];
